        x = y;
        this->x = 7;
    }
    bool operator ==(const CD& rhs)
    {
        return ((this->x == rhs.x) && CD::x == rhs.CD::x);
    }
    bool operator!=(const CD& rhs)
    {
        return!(this->x == rhs.x || CD::x == rhs.CD::x);
    }
};

